#include <format>
#include <iostream>
#include <string>

int main() {
    // Default formatting
    std::cout << std::format("int: {}, float: {}, string: {}\n", 42, 3.14, "hello");

    // Number formatting
    std::cout << std::format("hex: {:x}, HEX: {:X}, oct: {:o}, bin: {:b}\n", 255, 255, 255, 255);
    std::cout << std::format("padded hex: {:#010x}\n", 255);
    std::cout << std::format("float fixed: {:.4f}\n", 3.14159265);
    std::cout << std::format("float sci:   {:e}\n", 123456.789);
    std::cout << std::format("sign:  {:+}, {:+}\n", 42, -42);

    // Alignment
    std::cout << std::format("|{:>10}|{:<10}|{:^10}|\n", "right", "left", "center");
    std::cout << std::format("|{:0>10}|{:*<10}|{:-^10}|\n", 42, "hi", "mid");

    // Positional args
    std::cout << std::format("{0} {1} {0}\n", "ping", "pong");
}

#include <format>
#include <iostream>
#include <string>
#include <cstdint>

struct Color {
    uint8_t r, g, b;
};

template<>
struct std::formatter<Color> {
    bool hex_mode = false;

    constexpr auto parse(std::format_parse_context& ctx) {
        auto it = ctx.begin();
        if (it != ctx.end() && *it == 'x') {
            hex_mode = true;
            ++it;
        }
        return it;
    }

    auto format(const Color& c, std::format_context& ctx) const {
        if (hex_mode)
            return std::format_to(ctx.out(), "#{:02x}{:02x}{:02x}", c.r, c.g, c.b);
        return std::format_to(ctx.out(), "rgb({},{},{})", c.r, c.g, c.b);
    }
};

int main() {
    Color red{255, 0, 0};
    Color teal{0, 128, 128};

    std::cout << std::format("default: {}\n", red);
    std::cout << std::format("hex:     {:x}\n", red);
    std::cout << std::format("teal:    {:x}\n", teal);

    // format_to — write directly to a string
    std::string buf;
    std::format_to(std::back_inserter(buf), "colors: {} and {:x}", red, teal);
    std::cout << buf << '\n';

    // formatted_size
    std::size_t sz = std::formatted_size("{:.2f}", 3.14159);
    std::cout << "formatted_size of 3.14: " << sz << '\n';
}

#include <span>
#include <vector>
#include <array>
#include <iostream>

void print_span(std::span<const int> s) {
    std::cout << "[";
    for (size_t i = 0; i < s.size(); ++i) {
        if (i) std::cout << ", ";
        std::cout << s[i];
    }
    std::cout << "] (size=" << s.size() << ")\n";
}

void double_values(std::span<int> s) {
    for (auto& v : s) v *= 2;
}

int main() {
    int arr[] = {1, 2, 3, 4, 5};
    std::vector<int> vec = {10, 20, 30, 40, 50};
    std::array<int, 3> arr2 = {7, 8, 9};

    std::cout << "from raw array:  "; print_span(arr);
    std::cout << "from vector:     "; print_span(vec);
    std::cout << "from std::array: "; print_span(arr2);

    std::span<int> s{arr, 5};
    std::cout << "\nfirst(3):  "; print_span(s.first(3));
    std::cout << "last(2):   "; print_span(s.last(2));
    std::cout << "subspan(1,3): "; print_span(s.subspan(1, 3));

    double_values(s);
    std::cout << "\nafter doubling: "; print_span(s);
}

