#include <span>
#include <vector>
#include <array>
#include <iostream>
#include <cstddef>
#include <numeric>
#include <cstdint>

// XOR checksum over the raw bytes of any contiguous block of data
template<typename T>
uint8_t checksum(std::span<const T> data) {
    auto bytes = std::as_bytes(data);
    uint8_t sum = 0;
    for (auto b : bytes) sum ^= static_cast<uint8_t>(b);
    return sum;
}

// Fixed-size span (static extent) — accepts exactly 4 elements
void process_fixed(std::span<const int, 4> s) {
    std::cout << "fixed[0..3]: ";
    for (auto v : s) std::cout << v << " ";
    std::cout << '\n';
    std::cout << "compile-time size: " << s.size() << '\n';
}

// Sliding window sum — demonstrates subspan in algorithmic code
std::vector<int> sliding_sum(std::span<const int> data, std::size_t window) {
    std::vector<int> result;
    for (std::size_t i = 0; i + window <= data.size(); ++i) {
        auto sub = data.subspan(i, window);
        result.push_back(std::accumulate(sub.begin(), sub.end(), 0));
    }
    return result;
}

int main() {
    std::array<int, 4> fixed = {10, 20, 30, 40};
    process_fixed(fixed);

    std::vector<int> data = {1, 2, 3, 4, 5, 6};
    auto sums = sliding_sum(data, 3);
    std::cout << "sliding_sum(window=3): ";
    for (auto v : sums) std::cout << v << " ";
    std::cout << '\n';

    // as_bytes: XOR checksum of a uint32_t array
    std::array<uint32_t, 3> arr = {0x01020304, 0x05060708, 0x090A0B0C};
    auto cs = checksum(std::span<const uint32_t>{arr});
    std::cout << "checksum: 0x" << std::hex << (int)cs << '\n';
}
